// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Check validate field 氏名/メール/社員番号 -  max value 30 character (enter > 30 character)', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Check validate field 氏名/メール/社員番号 -  max value 30 character (enter > 30 character)', async function() {
    await driver.get("http://localhost:4200/admin-user/list-user");
    await driver.manage().window().setRect({ width: 1936, height: 1056 });
    await driver.findElement(By.css(".ant-form-item:nth-child(4) .ant-form-item-control-input-content")).click();
    await driver.findElement(By.id("create_template_form_nameAndEmail")).click();
    await driver.findElement(By.id("create_template_form_nameAndEmail")).sendKeys("aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa");
    await driver.findElement(By.css(".ant-form-item:nth-child(4) .ant-form-item-control-input-content")).click();
    await driver.findElement(By.css(".ant-form-item-explain-error")).click();
    assert(await driver.findElement(By.css(".ant-form-item-explain-error")).getText() == "30文字以内で入力してください。");
  });
});
